export function tabToPresetCategory(tab: TabKey): SchedulePresetCategory | null {
  switch (tab) {
    case 'rooms':
      return 'room';
    case 'doors':
      return 'door';
    case 'windows':
      return 'window';
    case 'assemblies':
      return 'material_assembly';
    default:
      return null;
  }
}

